	private int UpdateInfoBussness2AutresRevenu(HttpServletRequest request) {
		int nbr = 0;
		try {
			HttpSession sessionConnect = request.getSession();
			int IdAchatPP = Integer.parseInt(request.getParameter("IdAchatPP")
					.toString());
			String DescriptionActivite = request.getParameter(
					"DescriptionActivite").toString();
			int AnneeDepuis = Integer.parseInt(request.getParameter(
					"AnneeDepuis").toString());
			double RevenuMensuel = Double.parseDouble(request.getParameter(
					"RevenuMensuel").toString());
			nbr = WDao
					.UpdateBusiness2AutreRevenu(IdAchatPP, DescriptionActivite
							.replace("'", "''"), AnneeDepuis, RevenuMensuel,
							Integer.parseInt(sessionConnect.getAttribute(
									"IdClientConcerner").toString()),
							sessionConnect.getAttribute("NumDossierCreditD")
									.toString());
			if (nbr > 0) {
				request.setAttribute("UpdateSP", "ook");
			}
			List<WorkflowEntite> ListeVenteMensuelMoyenok = new ArrayList<>();
			ListeVenteMensuelMoyenok = WDao
					.ListeAutresRevenuBusiness2ClientD(sessionConnect
							.getAttribute("NumDossierCreditD").toString(),
							Integer.parseInt(sessionConnect.getAttribute(
									"IdClientConcerner").toString()));
			double TotalRevenuAutre = 0;
			for (WorkflowEntite wf : ListeVenteMensuelMoyenok) {
				TotalRevenuAutre = TotalRevenuAutre + wf.getRevenumensuelb2();
			}
			sessionConnect.setAttribute("TotalRevenuAutre", TotalRevenuAutre);
			sessionConnect.setAttribute("ListeAutreRevenuB2",
					ListeVenteMensuelMoyenok);

		} catch (Exception e) {
			e.printStackTrace();
		}
		return nbr;

	}

