	private void GestionProduitCredit(HttpServletRequest request) {
		try {
			HttpSession sessionConnect = request.getSession();
			DecimalFormat df = new DecimalFormat("0.00");
			String DescriptionProduitIL01 = request.getParameter(
					"DescriptionProduitIL01").toString();
			double MontantMinProduitIL01 = Double.parseDouble(request
					.getParameter("MontantMinProduitIL01").toString());
			double MontantMaxProduitIL01 = Double.parseDouble(request
					.getParameter("MontantMaxProduitIL01").toString());
			double TauxInteretProduitIL01 = Double.parseDouble(request
					.getParameter("TauxInteretProduitIL01").toString());
			double FraisDossierProduitIL01 = Double.parseDouble(request
					.getParameter("FraisDossierProduitIL01").toString());
			double CautionProduitIL01 = Double.parseDouble(request
					.getParameter("CautionProduitIL01").toString());

			double TauxInteretProduitILMensuel = TauxInteretProduitIL01 / 12;
			TauxInteretProduitILMensuel = Double.parseDouble(df
					.format(TauxInteretProduitILMensuel));

			if (request.getParameter("idproduitcreditvalide") == null
					|| request.getParameter("idproduitcreditvalide") == "") {
				int nbrUserSavePC = WDao.EnregistrementProduitCreditIL(
						DescriptionProduitIL01.replace("'", "''"),
						MontantMinProduitIL01, MontantMaxProduitIL01,
						TauxInteretProduitIL01, FraisDossierProduitIL01,
						CautionProduitIL01, TauxInteretProduitILMensuel);
				request.setAttribute("nbrUserSavePC", nbrUserSavePC);

				List<WorkflowEntite> ListeProduitCreditValider = new ArrayList<>();
				ListeProduitCreditValider = WDao.GetListeProduitCreditValider();
				sessionConnect.setAttribute("ListeProduitCreditValider",
						ListeProduitCreditValider);

			} else {
				int nbrUserUpdatePC = WDao.UpdateProduitCredit(
						Integer.parseInt(request.getParameter(
								"idproduitcreditvalide").toString()),
						DescriptionProduitIL01.replace("'", "''"),
						MontantMinProduitIL01, MontantMaxProduitIL01,
						TauxInteretProduitIL01, FraisDossierProduitIL01,
						CautionProduitIL01, TauxInteretProduitILMensuel);
				request.setAttribute("nbrUserUpdatePC", nbrUserUpdatePC);
				List<WorkflowEntite> ListeProduitCreditValider = new ArrayList<>();
				ListeProduitCreditValider = WDao.GetListeProduitCreditValider();
				sessionConnect.setAttribute("ListeProduitCreditValider",
						ListeProduitCreditValider);
			}
		} catch (Exception ex) {
			ex.printStackTrace();
		}
	}

