	private void TransfertDossierILTous(HttpServletRequest request) {
		try {
			int IdAgentCréditQuiTransfert = Integer.parseInt(request
					.getParameter("IdAgentCréditQuiTransfert").toString());
			int IdAgentCréditQuiATransfert = Integer.parseInt(request
					.getParameter("IdAgentCréditQuiATransfert").toString());
			String BrancheVPARA = request.getParameter("BrancheVPARA")
					.toString();
			String SuperviseurGLPARA = request
					.getParameter("SuperviseurGLPARA").toString();
			String InitialisateurILpara = request.getParameter(
					"InitialisateurILpara").toString();
			String AssignateurDossierCreditValuepara = request.getParameter(
					"AssignateurDossierCreditValuepara").toString();
			int IDBrancheVPARA = WDao
					.GetIdBrancheMICROPOPViaLibelle(BrancheVPARA);

			int IDSuperviseurGLPARA = WDao
					.GetIDUserViaNomsUser(SuperviseurGLPARA);

			int IDInitialisateurILpara = WDao
					.GetIDUserViaNomsUser(InitialisateurILpara);

			int IDAssignateurDossierCreditValuepara = WDao
					.GetIDUserViaNomsUser(AssignateurDossierCreditValuepara);

			String NomsACDestination = WDao
					.GetNomsUserViaId(IdAgentCréditQuiATransfert);

			if ((WDao.GetStatutUser(IdAgentCréditQuiTransfert).equals("Actif"))
					&& (WDao.GetStatutUser(IdAgentCréditQuiATransfert)
							.equals("Actif"))) {
				List<String> ListeNumDossierAnalyse = new ArrayList<>();

				ListeNumDossierAnalyse = WDao
						.GetListeNumDossierAnalyse(IdAgentCréditQuiTransfert);

				for (String NumDoss : ListeNumDossierAnalyse) {

					WDao.TransfererDossier(IdAgentCréditQuiATransfert, NumDoss,
							IDBrancheVPARA, IDSuperviseurGLPARA,
							IDAssignateurDossierCreditValuepara);
					WDao.UpdateInitialisateurDossierIL(NumDoss,
							IDInitialisateurILpara, NomsACDestination);
				}
				if (IdAgentCréditQuiTransfert != IdAgentCréditQuiATransfert) {
					WDao.UpdateStatutUserTransfert(IdAgentCréditQuiTransfert);
				}
				request.setAttribute("BrancheVPARA", BrancheVPARA);
				request.setAttribute("SuperviseurGLPARA", SuperviseurGLPARA);
				request.setAttribute("InitialisateurILpara",
						InitialisateurILpara);
				request.setAttribute("AssignateurDossierCreditValuepara",
						AssignateurDossierCreditValuepara);
				request.setAttribute("IdAgentCréditQuiTransfert",
						IdAgentCréditQuiTransfert);
				request.setAttribute("IdAgentCréditQuiATransfert",
						IdAgentCréditQuiATransfert);
				int nbrUserSaveok = 10;
				request.setAttribute("nbrUserSaveok", nbrUserSaveok);
			} else {
				request.setAttribute("BrancheVPARA", BrancheVPARA);
				request.setAttribute("SuperviseurGLPARA", SuperviseurGLPARA);
				request.setAttribute("InitialisateurILpara",
						InitialisateurILpara);
				request.setAttribute("AssignateurDossierCreditValuepara",
						AssignateurDossierCreditValuepara);
				request.setAttribute("IdAgentCréditQuiTransfert",
						IdAgentCréditQuiTransfert);
				request.setAttribute("IdAgentCréditQuiATransfert",
						IdAgentCréditQuiATransfert);
				int nbrUserSaveError = 101;
				request.setAttribute("nbrUserSaveError", nbrUserSaveError);
			}
		} catch (Exception ex) {
			ex.printStackTrace();
		}
	}

	private void EnregistrementReunionGprGL(HttpServletRequest request) {
		try {
			HttpSession sessionConnect = request.getSession();
			int idReunion = Integer.parseInt(request.getParameter("idReunion")
					.toString());
			// int cycleGrp = Integer.parseInt(request
			// .getParameter("cycleGrp").toString());
			String NomsMembreGroupeGL = request.getParameter(
					"NomsMembreGroupeGL").toString();
			int idMembre = WDao.GetIDClientGL(NomsMembreGroupeGL);
			double MontantRemboursEspere = Double.parseDouble(sessionConnect
					.getAttribute("MontantRemboursEspere").toString());
			double MontantRemboursReunion = Double.parseDouble(request
					.getParameter("MontantRemboursReunion").toString());

			double MontantEpargneGLEspere = Double.parseDouble(sessionConnect
					.getAttribute("MontantEpargneGLEspere").toString());
			double MontantEpargneGLReunion = Double.parseDouble(request
					.getParameter("MontantEpargneGLReunion").toString());

			String StatutEpargne = "";
			String StatutRemboursement = "";

			if (MontantEpargneGLReunion >= MontantEpargneGLEspere) {
				StatutEpargne = "1";
			} else {
				StatutEpargne = "0";
			}

			if (MontantRemboursReunion >= MontantRemboursEspere) {
				StatutRemboursement = "1";
			} else {
				StatutRemboursement = "0";
			}

			String delegationvalue = request.getParameter("DelegationValue");
			int idPresenceVerif = 0;
			idPresenceVerif = WDao
					.VerificationPresenceReunionPourEviterDuplication(
							idReunion, idMembre);
			if (idPresenceVerif == 0) {
				int nbrok = WDao.EnregistrementPresenceRunionGL(
						MontantRemboursEspere, MontantRemboursReunion,
						MontantEpargneGLEspere, MontantEpargneGLReunion,
						StatutRemboursement, StatutEpargne, idMembre,
						idReunion, delegationvalue);
				if (nbrok > 0) {
					request.setAttribute("nbrUserSave20", "100");
				}
			} else {
				request.setAttribute("error",
						"Desolé,ce membre posséde déja les informations sur le remboursement !!!");
			}

		} catch (Exception ex) {
			ex.printStackTrace();
		}
	}

