	private String GetProfilNameok(String ProfilUser) {
		String ProfilName = "";
		try {
			if (ProfilUser.equals("SC")) {
				ProfilName = "Service Client";
			} else if (ProfilUser.equals("ODP")) {
				ProfilName = "Officier du Portefeuille";
			} else if (ProfilUser.equals("DG")) {
				ProfilName = "Directeur Général";
			} else if (ProfilUser.equals("DGA")) {
				ProfilName = "Directeur Général Adjoint";
			} else if (ProfilUser.equals("CI")) {
				ProfilName = "Controle Interne";
			} else if (ProfilUser.equals("RC")) {
				ProfilName = "Risque et Conformité";
			} else if (ProfilUser.equals("ADMIN")) {
				ProfilName = "ADMIN";
			} else if (ProfilUser.equals("BM")) {
				ProfilName = "Branche Manager (BM)";
			} else if (ProfilUser.equals("SUP")) {
				ProfilName = "Superviseur";
			} else if (ProfilUser.equals("CA")) {
				ProfilName = "Agent de Crédit";
			}
		} catch (Exception ex) {
			ex.printStackTrace();
		}
		return ProfilName;
	}

	public static String formatMontant(long montant) {
		DecimalFormat df = new DecimalFormat("#,###");
		// Remplacer la virgule par un espace pour style français
		String formate = df.format(montant).replace(",", " ");
		return formate;
	}

