			List<WorkflowEntite> ListeGarntieDeposeClientIL = new ArrayList<>();
			ListeGarntieDeposeClientIL = WDao
					.ListeGarntieDeposeClientDPourModification(IdGarantie);
			String TypeGarantieGG = "";
			String DescriptionGG = "";
			int AnneeFabrication = 0;
			String EtatGG = "";
