	private void GetInformationUtilisateurs(HttpServletRequest request) {
		try {
			List<WorkflowEntite> ListeInformationTousUser = new ArrayList<>();
			int IdUser = Integer.parseInt(request.getParameter("numU")
					.toString());
			String nomsutilisateur = "";
			String telephoneutilisateur = "";
			String emailutilisateur = "";
			String statututilisateur = "";
			String loginutilisateur = "";
			String motpassutilisateur = "";
			String profilutilisateur = "";
			String brancheuse = "";
			int numcbsutilisateur = 0;
			ListeInformationTousUser = WDao
					.ListeInformationUserForUpdate(IdUser);
			for (WorkflowEntite wf : ListeInformationTousUser) {
				nomsutilisateur = wf.getNomsutilisateur();
				telephoneutilisateur = wf.getTelephoneutilisateur();
				emailutilisateur = wf.getEmailutilisateur();
				statututilisateur = wf.getStatututilisateur();
				loginutilisateur = wf.getLoginutilisateur();
				motpassutilisateur = wf.getMotpassutilisateur();
				profilutilisateur = wf.getProfilutilisateur();
				brancheuse = wf.getBrancheuse();
				numcbsutilisateur = wf.getNumcbsutilisateur();
			}
			request.setAttribute("IdUser", IdUser);
			request.setAttribute("nomsutilisateur", nomsutilisateur);
			request.setAttribute("telephoneutilisateur", telephoneutilisateur);
			request.setAttribute("emailutilisateur", emailutilisateur);
			request.setAttribute("statututilisateur", statututilisateur);
			request.setAttribute("loginutilisateur", loginutilisateur);
			// request.setAttribute("motpassutilisateur", motpassutilisateur);
			request.setAttribute("profilutilisateur", profilutilisateur);
			request.setAttribute("brancheuse", brancheuse);
			request.setAttribute("numcbsutilisateur", numcbsutilisateur);
		} catch (Exception ex) {
			ex.printStackTrace();
		}
	}

	private void ModificationInformationUtilisateurs(HttpServletRequest request) {
		try {
			HttpSession sessionConnect = request.getSession();
			int IdUser = Integer.parseInt(request.getParameter("IdUser")
					.toString());
			String nomsutilisateur = request.getParameter("nomsutilisateur")
					.toString();
			String telephoneutilisateur = request.getParameter(
					"telephoneutilisateur").toString();
			String emailutilisateur = request.getParameter("emailutilisateur")
					.toString();
			String loginutilisateur = request.getParameter("loginutilisateur")
					.toString();
			String motpassutilisateur = request.getParameter(
					"motpassutilisateur").toString();
			String statututilisateur = request
					.getParameter("statututilisateur").toString();
			String profilutilisateur = request
					.getParameter("profilutilisateur").toString();
			String brancheuse = request.getParameter("brancheuse").toString();
			int numcbsutilisateur = Integer.parseInt(request.getParameter(
					"numcbsutilisateur").toString());
			int idbrancheUser = WDao.GetIdBrancheMICROPOPViaLibelle(brancheuse);
			int connected = 0;

			if (!isValidPassword(motpassutilisateur)) {
				request.setAttribute(
						"error",
						"Mot de passe invalide : "
								+ "minimum 14 caractères, au moins une lettre, un chiffre, "
								+ "et sans caractères interdits.");
			}

			else {
				int nbrL = WDao.updateUtilisateur(IdUser,
						nomsutilisateur.replace("'", "''"),
						telephoneutilisateur,
						emailutilisateur.replace("'", "''"), statututilisateur,
						loginutilisateur, hashPassword(motpassutilisateur),
						idbrancheUser, profilutilisateur, numcbsutilisateur,
						connected);
				if (nbrL > 0) {
					request.setAttribute("Nbrl", "ok");
				}
			}
			List<WorkflowEntite> ListeInformationTousUser = new ArrayList<>();
			ListeInformationTousUser = WDao.ListeInformationTousUserCreate();
			sessionConnect.setAttribute("ListeInformationTousUser",
					ListeInformationTousUser);
		} catch (Exception ex) {
			ex.printStackTrace();
		}
	}

	private void ModificationMotPasseUtilisateurs(HttpServletRequest request,
			HttpServletResponse response) {
		try {
			HttpSession sessionConnect = request.getSession();
			int connected = 1;
			String Actuelmotpassutilisateur = request.getParameter(
					"Actuelmotpassutilisateur").toString();
			String Nouveaumotpassutilisateur = request.getParameter(
					"Nouveaumotpassutilisateur").toString();
			String CNmotpassutilisateur = request.getParameter(
					"CNmotpassutilisateur").toString();
			String ActualPwdU = WDao
					.GetActuelPWDUser(Integer.parseInt(sessionConnect
							.getAttribute("IduserC").toString()));
			if (hashPassword(Actuelmotpassutilisateur).equals(ActualPwdU)) {
				if ((!isValidPassword(Nouveaumotpassutilisateur))
						|| (!isValidPassword(CNmotpassutilisateur))) {
					request.setAttribute(
							"error",
							"Mot de passe invalide : "
									+ "minimum 14 caractères, au moins une lettre, un chiffre, "
									+ "et sans caractères interdits.");

					request.getRequestDispatcher("ChangementPWDPage.jsp")
							.forward(request, response);
				}

				else {
					// verification si les deux mot de passe correspondent
					if (Nouveaumotpassutilisateur.equals(CNmotpassutilisateur)) {
						int nbr = WDao.updateMotPasseUtilisateur(
								Integer.parseInt(sessionConnect.getAttribute(
										"IduserC").toString()),
								hashPassword(Nouveaumotpassutilisateur),
								connected);
						if (nbr > 0) {
							request.setAttribute("reussiteok", "ok");
						}
						request.getRequestDispatcher("HomePage.jsp").forward(
								request, response);

					} else {
						request.setAttribute("error",
								"Desoler,les deux mot de passe ne correspondent pas !!!");
						request.getRequestDispatcher("ChangementPWDPage.jsp")
								.forward(request, response);
					}
				}
			} else {
				request.setAttribute("error",
						"Desoler,l'actuel mot de passe ne corresponde pas !!!");
				request.getRequestDispatcher("ChangementPWDPage.jsp").forward(
						request, response);
			}

		} catch (Exception ex) {
			ex.printStackTrace();
		}
	}

