	private void getInfoGroupeRecapServlet(HttpServletRequest request,
			HttpServletResponse response) {
		try {

			String code = request.getParameter("code");
			List<WorkflowEntite> ListeInformationGroupeGL = new ArrayList<>();
			int NumeroGroupeCBS = 0;
			int cycleRecap = 0;
			String NomGroupeLisanga = "";
			String AdresseGroupe = "";
			String ProvinceGroupe = "";
			String JourReunionGroupe = "";
			String HeureReunionGroupe = "";
			String NumeroTelephoneGroupe = "";
			String PromoteurGroupe = "";
			String SuperviseurGL = "";
			String NomsChefAgence = "";
			ListeInformationGroupeGL = WDao
					.GetListeInformationGroupeGLRecap(Integer.parseInt(code));
			for (WorkflowEntite wg : ListeInformationGroupeGL) {
				NumeroGroupeCBS = wg.getNumerogroupecbslisanga();
				NomGroupeLisanga = wg.getNomgroupelisanga();
				AdresseGroupe = wg.getAdressegroupelisanga();
				ProvinceGroupe = wg.getProvincegroupelisanga();
				JourReunionGroupe = wg.getJourreuniongroupelisanga();
				HeureReunionGroupe = wg.getHeurereuniongroupelisanga();
				NumeroTelephoneGroupe = wg.getNumerotelephonegroupelisanga();
				PromoteurGroupe = wg.getPromoteurgroupelisanga();
				SuperviseurGL = wg.getSuperviseurgllisanga();
				NomsChefAgence = wg.getNomchefagencemv();
				cycleRecap = wg.getNbrcyclegroupelisanga() + 1;
			}

			if (ListeInformationGroupeGL.size() > 0) {
				response.setContentType("application/json");
				PrintWriter out = response.getWriter();

				out.print("{" + "\"NomGroupeLisanga\": \"" + NomGroupeLisanga
						+ "\"," + "\"AdresseGroupe\": \"" + AdresseGroupe
						+ "\"," + "\"ProvinceGroupe\": \"" + ProvinceGroupe
						+ "\"," + "\"JourReunionGroupe\": \""
						+ JourReunionGroupe + "\","
						+ "\"HeureReunionGroupe\": \"" + HeureReunionGroupe
						+ "\"," + "\"NumeroTelephoneGroupe\": \""
						+ NumeroTelephoneGroupe + "\","
						+ "\"PromoteurGroupe\": \"" + PromoteurGroupe + "\","
						+ "\"SuperviseurGL\": \"" + SuperviseurGL + "\","
						+ "\"NomsChefAgence\": \"" + NomsChefAgence + "\","
						+ "\"cycleRecap\": \"" + cycleRecap + "\"" + "}");

				out.flush();
			}

		} catch (Exception ex) {
			ex.printStackTrace();
		}
	}

	private void RecapGroupeGL(HttpServletRequest request,
			HttpServletResponse response) {
		try {
			HttpSession sessionConnect = request.getSession();
			List<WorkflowEntite> ListeDossierCreditGLFonctionStatutEtProfilUtilisateur = new ArrayList<>();
			int NumeroGroupeCBS = Integer.parseInt(request.getParameter(
					"NumeroGroupeCBS").toString());
			int NbrHommeGroupe = Integer.parseInt(request.getParameter(
					"NbrHommeGroupe").toString());
			int NbrFemmeGroupe = Integer.parseInt(request.getParameter(
					"NbrFemmeGroupe").toString());
			int NbrCycleGroupe = Integer.parseInt(request.getParameter(
					"NbrCycleGroupe").toString());
			String CategorieRisqueGroupe = request.getParameter(
					"CategorieRisqueGroupe").toString();
			String etatGroupGL = "Creation";
			String NomsChefAgenceMcpop = request.getParameter("NomsChefAgence")
					.toString();
			String EtatGp = WDao
					.GetListeEtatGroupeLisangaPourRecapBus(NumeroGroupeCBS);
			if (EtatGp.equals("Terminer")) {
				int id_dcr_grp_sol = WDao
						.GetVerificationSiGroupePossedeUnPretEncour(NumeroGroupeCBS);
				if (id_dcr_grp_sol > 0) {
					request.setAttribute("error",
							"Désolé,ce groupe posséde déja un encour crédit !!!");
				} else {

					int Lg = WDao.updateGroupeLisangaForRecap(NumeroGroupeCBS,
							NbrHommeGroupe, NbrFemmeGroupe, NbrCycleGroupe,
							CategorieRisqueGroupe, etatGroupGL,
							NomsChefAgenceMcpop.replace("'", "''"));
					if (Lg > 0) {
						request.setAttribute("ok",
								"Félicitation,Le récap est effectuer avec succés !!!");
						List<WorkflowEntite> ListeDossierCreditGLCAetapeCreation = new ArrayList<>();
						List<WorkflowEntite> ListeDossierCreditGLCAetapeAnalyse = new ArrayList<>();
						ListeDossierCreditGLCAetapeCreation = WDao
								.ListeDossierCreditGLCAetapeCreation(Integer
										.parseInt(sessionConnect.getAttribute(
												"IduserC").toString()));
						ListeDossierCreditGLCAetapeAnalyse = WDao
								.ListeDossierCreditGLCAetapeAnalyse(Integer
										.parseInt(sessionConnect.getAttribute(
												"IduserC").toString()));
						ListeDossierCreditGLFonctionStatutEtProfilUtilisateur
								.addAll(ListeDossierCreditGLCAetapeCreation);
						ListeDossierCreditGLFonctionStatutEtProfilUtilisateur
								.addAll(ListeDossierCreditGLCAetapeAnalyse);

						sessionConnect
								.setAttribute(
										"ListeDossierCreditGLFonctionStatutEtProfilUtilisateur",
										ListeDossierCreditGLFonctionStatutEtProfilUtilisateur);
					} else {
						request.setAttribute("error",
								"Désole,échec récap du groupe !!!");
					}

				}

			} else {
				request.setAttribute(
						"error",
						"Désole,ce groupe posséde déja des dossiers encour de traitement ou soit non implementer !!!");
			}
			request.getRequestDispatcher("CreaditGL.jsp").forward(request,
					response);

		} catch (Exception ex) {
			ex.printStackTrace();
		}
	}

