	public String hashPassword(String password) {
		try {
			MessageDigest messageDigest = MessageDigest.getInstance("MD5");
			byte[] hashedBytes = messageDigest.digest(password.getBytes());

			// Convertir le tableau de bytes en une chaîne hexadécimale
			StringBuilder hexString = new StringBuilder();
			for (byte b : hashedBytes) {
				hexString.append(String.format("%02x", b));
			}
			return hexString.toString();
		} catch (NoSuchAlgorithmException e) {
			throw new RuntimeException("MD5 Algorithm not found", e);
		}
	}

	public String GetLibProdCre(double MontantDemandeValue) {
		String ProduitFinancierValue = "";
		try {
			if (MontantDemandeValue >= 501 && MontantDemandeValue <= 1000) {
				ProduitFinancierValue = "Credit LISUNGI 1 (501 - 1000)";

			} else if (MontantDemandeValue >= 1001
					&& MontantDemandeValue <= 5000) {
				ProduitFinancierValue = "Credit LISUNGI 2 (1001 - 5000)";

			} else if (MontantDemandeValue >= 5001
					&& MontantDemandeValue <= 10000) {
				ProduitFinancierValue = "Credit MOSALA (5001 - 10000)";

			} else if (MontantDemandeValue >= 10001
					&& MontantDemandeValue <= 14999) {
				ProduitFinancierValue = "Credit MOSALA 1 (10001 - 14999)";

			} else if (MontantDemandeValue >= 15000
					&& MontantDemandeValue <= 30000) {
				ProduitFinancierValue = "Credit MOSALA 2 (15000 - 30000)";
			} else if (MontantDemandeValue >= 30001
					&& MontantDemandeValue <= 100000) {
				ProduitFinancierValue = "Credit MOSALA 3 (30001 - 100000)";
			}
		} catch (Exception e) {
			throw new RuntimeException("", e);
		}
		return ProduitFinancierValue;
	}

