						// WDao.UpdateNumClientCbs(idclientok,
						// NumDossierCredit);
						WDao.ModificationCautionDansComiteIL(NumDossierCredit,
								GarNum);
						// WDao.ModificationTauxCautionModifierDansComiteIL(
						// NumDossierCredit, TauxCautionModifValue);
						sessionConnect.setAttribute("cautionF", GarNum);
						sessionConnect.setAttribute("NumCbsCliValue",
								idclientok);
						request.setAttribute("TauxCautionModifValue1",
								TauxCautionModifValue);
						sessionConnect.setAttribute("TauxCautionModifValue",
								TauxCautionModifValue);
						request.setAttribute(
								"ok",
								"Felicitation,le postage est effectuer avec succés dans le CoreBanking Systéme !!!");
