	private void GetInformationResumePropositionDynamique(
			HttpServletRequest request) {
		try {
			HttpSession sessionConnect = request.getSession();
			// pour resume et proposition
			double MontantDemandeRP = WDao
					.GetMontantDemande(Integer.parseInt(sessionConnect
							.getAttribute("IdClientConcerner").toString()),
							sessionConnect.getAttribute("NumDossierCreditD")
									.toString());
			sessionConnect.setAttribute("MontantDemandeRP", MontantDemandeRP);
			int NbrEcheanceDemande = WDao
					.GetNbrEcheanceDemande(Integer.parseInt(sessionConnect
							.getAttribute("IdClientConcerner").toString()),
							sessionConnect.getAttribute("NumDossierCreditD")
									.toString());
			sessionConnect.setAttribute("NbrEcheanceDemande",
					NbrEcheanceDemande);

			int CapacitePayementDemande = WDao.GetCapacitePayementDemande(
					Integer.parseInt(sessionConnect.getAttribute(
							"IdClientConcerner").toString()), sessionConnect
							.getAttribute("NumDossierCreditD").toString());
			sessionConnect.setAttribute("CapacitePayementDemande",
					CapacitePayementDemande);

			String ProduitCreditDemandeRP = WDao.GetProduitCreditDemande(
					Integer.parseInt(sessionConnect.getAttribute(
							"IdClientConcerner").toString()), sessionConnect
							.getAttribute("NumDossierCreditD").toString());
			sessionConnect.setAttribute("ProduitCreditDemandeRP",
					ProduitCreditDemandeRP);

			double ChiffreAffairesVentes = WDao.CalculChiffreAffairesVentes(
					Integer.parseInt(sessionConnect.getAttribute(
							"IdClientConcerner").toString()), sessionConnect
							.getAttribute("NumDossierCreditD").toString());
			sessionConnect.setAttribute("ChiffreAffairesVentes",
					ChiffreAffairesVentes);
			DecimalFormat df = new DecimalFormat("0.00");

			List<WorkflowEntite> ListeProduitProductionUsineFabrication = new ArrayList<>();
			ListeProduitProductionUsineFabrication = WDao
					.GetListeProduitProductionUsineFabrication(sessionConnect
							.getAttribute("NumDossierCreditD").toString());

			double CoutMarchandiseVendue = 0;

			if (ListeProduitProductionUsineFabrication.size() == 0) {
				CoutMarchandiseVendue = WDao.CalculCoutMarchandiseVendue(
						Integer.parseInt(sessionConnect.getAttribute(
								"IdClientConcerner").toString()),
						sessionConnect.getAttribute("NumDossierCreditD")
								.toString());
				CoutMarchandiseVendue = Double.parseDouble(df
						.format(CoutMarchandiseVendue));
				sessionConnect.setAttribute("CoutMarchandiseVendue",
						CoutMarchandiseVendue);
			} else {
				CoutMarchandiseVendue = WDao
						.GetCAMVProductionAmeliorer(sessionConnect
								.getAttribute("NumDossierCreditD").toString());
				CoutMarchandiseVendue = Double.parseDouble(df
						.format(CoutMarchandiseVendue));
				sessionConnect.setAttribute("CoutMarchandiseVendue",
						CoutMarchandiseVendue);
			}

			double ProfitBruteRP = ChiffreAffairesVentes
					- CoutMarchandiseVendue;
			sessionConnect.setAttribute("ProfitBruteRP", ProfitBruteRP);

			double DepenseOperationnelleRP = WDao.CalculDepenseOperationnelle(
					Integer.parseInt(sessionConnect.getAttribute(
							"IdClientConcerner").toString()), sessionConnect
							.getAttribute("NumDossierCreditD").toString());
			sessionConnect.setAttribute("DepenseOperationnelleRP",
					DepenseOperationnelleRP);

			double ProfilNetRP = ProfitBruteRP - DepenseOperationnelleRP;
			sessionConnect.setAttribute("ProfilNetRP", ProfilNetRP);

			double TotalAutreRevenuNet = WDao
					.CalculTotalAutreRevenuNet(Integer.parseInt(sessionConnect
							.getAttribute("IdClientConcerner").toString()),
							sessionConnect.getAttribute("NumDossierCreditD")
									.toString());
			sessionConnect.setAttribute("TotalAutreRevenuNet",
					TotalAutreRevenuNet);

			int TotalDepensePrive = 0;
			// int ContributionClientDansDF = WDao
			// .GetContributionClientDF(Integer.parseInt(sessionConnect
			// .getAttribute("IdClientConcerner").toString()),
			// sessionConnect.getAttribute("NumDossierCreditD")
			// .toString());
			// if ((ContributionClientDansDF == 0)
			// || (ContributionClientDansDF == 100)) {
			TotalDepensePrive = WDao
					.CalculTotalDepensePrive(Integer.parseInt(sessionConnect
							.getAttribute("IdClientConcerner").toString()),
							sessionConnect.getAttribute("NumDossierCreditD")
									.toString());
			sessionConnect.setAttribute("TotalDepensePrive", TotalDepensePrive);
			// } else {
			// int TotalDepensePrive2 = WDao.CalculTotalDepensePrive(Integer
			// .parseInt(sessionConnect.getAttribute(
			// "IdClientConcerner").toString()),
			// sessionConnect.getAttribute("NumDossierCreditD")
			// .toString());
			// TotalDepensePrive = (int) ((TotalDepensePrive2 *
			// ContributionClientDansDF) / 100);
			// sessionConnect.setAttribute("TotalDepensePrive",
			// TotalDepensePrive);
			// }

			double capacitepaieRP = 0;
			capacitepaieRP = (ProfilNetRP + TotalAutreRevenuNet)
					- TotalDepensePrive;
			/*
			 * if (Integer.parseInt(sessionConnect.getAttribute("CycleValue")
			 * .toString()) == 1) { capacitepaieRP = (((ProfilNetRP +
			 * TotalAutreRevenuNet) - TotalDepensePrive) * 40) / 100; } else if
			 * (Integer.parseInt(sessionConnect.getAttribute(
			 * "CycleValue").toString()) == 2) { capacitepaieRP = (((ProfilNetRP
			 * + TotalAutreRevenuNet) - TotalDepensePrive) * 60) / 100; } else
			 * if (Integer.parseInt(sessionConnect.getAttribute(
			 * "CycleValue").toString()) >= 3) { capacitepaieRP = (((ProfilNetRP
			 * + TotalAutreRevenuNet) - TotalDepensePrive) * 70) / 100; }
			 */
			capacitepaieRP = Double.parseDouble(df.format(capacitepaieRP));
			sessionConnect.setAttribute("capacitepaieRP", capacitepaieRP);

			double capacitepaieRPCycle1 = 0;
			double capacitepaieRPCycle2 = 0;
			double capacitepaieRPCycle3 = 0;

			if (Integer.parseInt(sessionConnect.getAttribute("CycleValue")
					.toString()) == 1) {
				capacitepaieRPCycle1 = (((ProfilNetRP + TotalAutreRevenuNet) - TotalDepensePrive) * WDao
						.GetValeurCapaciteCycle1()) / 100;
			} else if (Integer.parseInt(sessionConnect.getAttribute(
					"CycleValue").toString()) == 2) {
				capacitepaieRPCycle1 = (((ProfilNetRP + TotalAutreRevenuNet) - TotalDepensePrive) * WDao
						.GetValeurCapaciteCycle1()) / 100;
				capacitepaieRPCycle2 = (((ProfilNetRP + TotalAutreRevenuNet) - TotalDepensePrive) * WDao
						.GetValeurCapaciteCycle2()) / 100;
			} else if (Integer.parseInt(sessionConnect.getAttribute(
					"CycleValue").toString()) >= 3) {
				capacitepaieRPCycle1 = (((ProfilNetRP + TotalAutreRevenuNet) - TotalDepensePrive) * WDao
						.GetValeurCapaciteCycle1()) / 100;
				capacitepaieRPCycle2 = (((ProfilNetRP + TotalAutreRevenuNet) - TotalDepensePrive) * WDao
						.GetValeurCapaciteCycle2()) / 100;
				capacitepaieRPCycle3 = (((ProfilNetRP + TotalAutreRevenuNet) - TotalDepensePrive) * WDao
						.GetValeurCapaciteCyclePlus3()) / 100;
			}
			capacitepaieRPCycle1 = Double.parseDouble(df
					.format(capacitepaieRPCycle1));
			capacitepaieRPCycle2 = Double.parseDouble(df
					.format(capacitepaieRPCycle2));
			capacitepaieRPCycle3 = Double.parseDouble(df
					.format(capacitepaieRPCycle3));

			sessionConnect.setAttribute("capacitepaieRPCycle1",
					capacitepaieRPCycle1);
			sessionConnect.setAttribute("capacitepaieRPCycle2",
					capacitepaieRPCycle2);
			sessionConnect.setAttribute("capacitepaieRPCycle3",
					capacitepaieRPCycle3);

			int cashBussness = WDao
					.CalculCashBussness(Integer.parseInt(sessionConnect
							.getAttribute("IdClientConcerner").toString()),
							sessionConnect.getAttribute("NumDossierCreditD")
									.toString());

			int CashAlaMaisonRP = WDao
					.CalculCashAlaMaison(Integer.parseInt(sessionConnect
							.getAttribute("IdClientConcerner").toString()),
							sessionConnect.getAttribute("NumDossierCreditD")
									.toString());
			sessionConnect.setAttribute("CashAlaMaisonRP", CashAlaMaisonRP
					+ cashBussness);

			int CashEnBanqueRP = WDao
					.CalculCashEnBanque(Integer.parseInt(sessionConnect
							.getAttribute("IdClientConcerner").toString()),
							sessionConnect.getAttribute("NumDossierCreditD")
									.toString());
			sessionConnect.setAttribute("CashEnBanqueRP", CashEnBanqueRP);

			int CreanceRP = WDao
					.CalculCreance(Integer.parseInt(sessionConnect
							.getAttribute("IdClientConcerner").toString()),
							sessionConnect.getAttribute("NumDossierCreditD")
									.toString());
			sessionConnect.setAttribute("CreanceRP", CreanceRP);

			int AutresStockRP = WDao
					.CalculAutresStock(Integer.parseInt(sessionConnect
							.getAttribute("IdClientConcerner").toString()),
							sessionConnect.getAttribute("NumDossierCreditD")
									.toString());

			int StockRP = WDao
					.CalculStock(Integer.parseInt(sessionConnect.getAttribute(
							"IdClientConcerner").toString()), sessionConnect
							.getAttribute("NumDossierCreditD").toString());
			sessionConnect.setAttribute("StockRP", StockRP + AutresStockRP);

			int TOTactifCirculantRP = CashAlaMaisonRP + CashEnBanqueRP
					+ CreanceRP + StockRP + cashBussness + AutresStockRP;
			sessionConnect.setAttribute("TOTactifCirculantRP",
					TOTactifCirculantRP);

			int MeubleRP = WDao
					.CalculMeuble(Integer.parseInt(sessionConnect.getAttribute(
							"IdClientConcerner").toString()), sessionConnect
							.getAttribute("NumDossierCreditD").toString());
			sessionConnect.setAttribute("MeubleRP", MeubleRP);

			int EquipementOutils = WDao
					.CalculEquipementOutils(Integer.parseInt(sessionConnect
							.getAttribute("IdClientConcerner").toString()),
							sessionConnect.getAttribute("NumDossierCreditD")
									.toString());
			sessionConnect.setAttribute("EquipementOutils", EquipementOutils);

			int VehiculeRP = WDao
					.CalculVehicule(Integer.parseInt(sessionConnect
							.getAttribute("IdClientConcerner").toString()),
							sessionConnect.getAttribute("NumDossierCreditD")
									.toString());
			sessionConnect.setAttribute("VehiculeRP", VehiculeRP);

			int LocalCommercialRP = WDao
					.CalculLocalCommercial(Integer.parseInt(sessionConnect
							.getAttribute("IdClientConcerner").toString()),
							sessionConnect.getAttribute("NumDossierCreditD")
									.toString());
			sessionConnect.setAttribute("LocalCommercialRP", LocalCommercialRP);

			int AutresRP = WDao
					.CalculAutres(Integer.parseInt(sessionConnect.getAttribute(
							"IdClientConcerner").toString()), sessionConnect
							.getAttribute("NumDossierCreditD").toString());
			sessionConnect.setAttribute("AutresRP", AutresRP);

			int TotalActifImmobilier = MeubleRP + EquipementOutils + VehiculeRP
					+ LocalCommercialRP + AutresRP;
			sessionConnect.setAttribute("TotalActifImmobilier",
					TotalActifImmobilier);

			int TotalActifRP = TotalActifImmobilier + TOTactifCirculantRP;
			sessionConnect.setAttribute("TotalActifRP", TotalActifRP);

			int LongTermeRP = WDao
					.CalculLongTerme(Integer.parseInt(sessionConnect
							.getAttribute("IdClientConcerner").toString()),
							sessionConnect.getAttribute("NumDossierCreditD")
									.toString());
			sessionConnect.setAttribute("LongTermeRP", LongTermeRP);

			int CourtTermeRP = WDao
					.CalculCourtTerme(Integer.parseInt(sessionConnect
							.getAttribute("IdClientConcerner").toString()),
							sessionConnect.getAttribute("NumDossierCreditD")
									.toString());
			sessionConnect.setAttribute("CourtTermeRP", CourtTermeRP);

			int TotalPassif = CourtTermeRP + LongTermeRP;
			sessionConnect.setAttribute("TotalPassif", TotalPassif);

			int CapitalPropreRP = TotalActifRP - TotalPassif;
			sessionConnect.setAttribute("CapitalPropreRP", CapitalPropreRP);

			List<WorkflowEntite> ListeRisquesPrincipauxMitigationBusiness1Resume = new ArrayList<>();
			ListeRisquesPrincipauxMitigationBusiness1Resume = WDao
					.ListeRisquesPrincipauxMitigationBusiness1Resume(
							sessionConnect.getAttribute("NumDossierCreditD")
									.toString(), Integer
									.parseInt(sessionConnect.getAttribute(
											"IdClientConcerner").toString()));

			if (ListeRisquesPrincipauxMitigationBusiness1Resume.size() > 0) {
				String LibelR1 = ListeRisquesPrincipauxMitigationBusiness1Resume
						.get(0).getLibellerisquesprincipauxb1();
				String MitR1 = ListeRisquesPrincipauxMitigationBusiness1Resume
						.get(0).getMitigation();

				String LibelR2 = ListeRisquesPrincipauxMitigationBusiness1Resume
						.get(1).getLibellerisquesprincipauxb1();
				String MitR2 = ListeRisquesPrincipauxMitigationBusiness1Resume
						.get(1).getMitigation();

				String LibelR3 = ListeRisquesPrincipauxMitigationBusiness1Resume
						.get(2).getLibellerisquesprincipauxb1();
				String MitR3 = ListeRisquesPrincipauxMitigationBusiness1Resume
						.get(2).getMitigation();

				sessionConnect.setAttribute("LibelR1", LibelR1);
				sessionConnect.setAttribute("MitR1", MitR1);
				sessionConnect.setAttribute("LibelR2", LibelR2);
				sessionConnect.setAttribute("MitR2", MitR2);
				sessionConnect.setAttribute("LibelR3", LibelR3);
				sessionConnect.setAttribute("MitR3", MitR3);
			}

			double DSR = WDao
					.CalculDSR(Integer.parseInt(sessionConnect.getAttribute(
							"IdClientConcerner").toString()), sessionConnect
							.getAttribute("NumDossierCreditD").toString(),
							capacitepaieRP);
			sessionConnect.setAttribute("DSR", DSR);

			double RatioGarantie = WDao
					.CalculRatioGarantie(Integer.parseInt(sessionConnect
							.getAttribute("IdClientConcerner").toString()),
							sessionConnect.getAttribute("NumDossierCreditD")
									.toString());
			sessionConnect.setAttribute("RatioGarantie", RatioGarantie);

			double RatioLiquite = WDao
					.CalculRatioLiquite(Integer.parseInt(sessionConnect
							.getAttribute("IdClientConcerner").toString()),
							sessionConnect.getAttribute("NumDossierCreditD")
									.toString(), TOTactifCirculantRP);
			sessionConnect.setAttribute("RatioLiquite", RatioLiquite);

			double LevierFinancier = WDao
					.CalculLevierFinancier(Integer.parseInt(sessionConnect
							.getAttribute("IdClientConcerner").toString()),
							sessionConnect.getAttribute("NumDossierCreditD")
									.toString(), TOTactifCirculantRP);
			sessionConnect.setAttribute("LevierFinancier", LevierFinancier);

			double RatioEndettement = WDao
					.CalculRatioEndettement(Integer.parseInt(sessionConnect
							.getAttribute("IdClientConcerner").toString()),
							sessionConnect.getAttribute("NumDossierCreditD")
									.toString(), CapitalPropreRP);
			sessionConnect.setAttribute("RatioEndettement", RatioEndettement);

			double RotationStock = WDao.CalculRotationStock(
					CoutMarchandiseVendue, TOTactifCirculantRP);
			sessionConnect.setAttribute("RotationStock", RotationStock);

			// Resume et Proposition par rapport a la baisse saison de vente

			double ChiffreAffairesVentesBaisseSaison = WDao
					.GetChiffreAffaireBaisseSaison(sessionConnect.getAttribute(
							"NumDossierCreditD").toString());
			sessionConnect.setAttribute("ChiffreAffairesVentesBaisseSaison",
					ChiffreAffairesVentesBaisseSaison);
			// DecimalFormat df2 = new DecimalFormat("0.00");
			double CoutMarchandiseVendueBaisseSaison = 0;
			if (ListeProduitProductionUsineFabrication.size() == 0) {
				CoutMarchandiseVendueBaisseSaison = WDao
						.CalculCoutMarchandiseVendueBaisseSaison(Integer
								.parseInt(sessionConnect.getAttribute(
										"IdClientConcerner").toString()),
								sessionConnect
										.getAttribute("NumDossierCreditD")
										.toString());
				CoutMarchandiseVendueBaisseSaison = Double.parseDouble(df
						.format(CoutMarchandiseVendueBaisseSaison));
				sessionConnect.setAttribute(
						"CoutMarchandiseVendueBaisseSaison",
						CoutMarchandiseVendueBaisseSaison);
			} else {
				CoutMarchandiseVendue = WDao
						.GetCAMVProductionAmeliorer(sessionConnect
								.getAttribute("NumDossierCreditD").toString());
				CoutMarchandiseVendue = Double.parseDouble(df
						.format(CoutMarchandiseVendue));
				sessionConnect.setAttribute("CoutMarchandiseVendue",
						CoutMarchandiseVendue);
			}

			double ProfitBruteRPBaisseVente = ChiffreAffairesVentesBaisseSaison
					- CoutMarchandiseVendueBaisseSaison;
			sessionConnect.setAttribute("ProfitBruteRPBaisseVente",
					ProfitBruteRPBaisseVente);
			double ProfilNetRPBaisseSaison = 0;
			if (ChiffreAffairesVentesBaisseSaison == 0) {
				ProfilNetRPBaisseSaison = 0;
			} else {
				ProfilNetRPBaisseSaison = ProfitBruteRPBaisseVente
						- DepenseOperationnelleRP;
			}
			sessionConnect.setAttribute("ProfilNetRPBaisseSaison",
					ProfilNetRPBaisseSaison);
			double capacitepaieRPBaisseSaison = 0;
			if (ProfilNetRPBaisseSaison == 0) {
				capacitepaieRPBaisseSaison = 0;
			} else {
				capacitepaieRPBaisseSaison = (ProfilNetRPBaisseSaison + TotalAutreRevenuNet)
						- TotalDepensePrive;
				/*
				 * if
				 * (Integer.parseInt(sessionConnect.getAttribute("CycleValue")
				 * .toString()) == 1) { capacitepaieRPBaisseSaison =
				 * (((ProfilNetRPBaisseSaison + TotalAutreRevenuNet) -
				 * TotalDepensePrive) * 40) / 100; } else if
				 * (Integer.parseInt(sessionConnect.getAttribute(
				 * "CycleValue").toString()) == 2) { capacitepaieRPBaisseSaison
				 * = (((ProfilNetRPBaisseSaison + TotalAutreRevenuNet) -
				 * TotalDepensePrive) * 60) / 100; } else if
				 * (Integer.parseInt(sessionConnect.getAttribute(
				 * "CycleValue").toString()) >= 3) { capacitepaieRPBaisseSaison
				 * = (((ProfilNetRPBaisseSaison + TotalAutreRevenuNet) -
				 * TotalDepensePrive) * 70) / 100; }
				 */
			}
			capacitepaieRPBaisseSaison = Double.parseDouble(df
					.format(capacitepaieRPBaisseSaison));
			sessionConnect.setAttribute("capacitepaieRPBaisseSaison",
					capacitepaieRPBaisseSaison);

			// Fin Resume et Proposition par rapport a la baisse saison de
			// vente
		} catch (Exception ex) {

		}
	}

	private void SupInformationVenteMensuelleMoyen(HttpServletRequest request) {
		try {
			HttpSession sessionConnect = request.getSession();
			int IdVMM = Integer.parseInt(request.getParameter("IdVMM")
					.toString());
			WDao.UpdateBusiness2VenteMensuelMoyen(IdVMM);
			List<WorkflowEntite> ListeVenteMensuelMoyen = new ArrayList<>();
			ListeVenteMensuelMoyen = WDao
					.ListeVenteMensuelMoyenClientD(sessionConnect.getAttribute(
							"NumDossierCreditD").toString());
			double MontantTotalVenteMoyenneMensuel = 0;

			for (WorkflowEntite wf : ListeVenteMensuelMoyen) {
				MontantTotalVenteMoyenneMensuel = MontantTotalVenteMoyenneMensuel
						+ wf.getMontantventemensuelmoyen();
			}
			double MontantTotalVenteMoyenneMensuelM = 0;
			if (ListeVenteMensuelMoyen.size() > 0) {
				MontantTotalVenteMoyenneMensuelM = MontantTotalVenteMoyenneMensuel
						/ ListeVenteMensuelMoyen.size();
			} else {
				MontantTotalVenteMoyenneMensuelM = 0;
			}
			sessionConnect.setAttribute("MontantTotalVenteMoyenneMensuelM",
					MontantTotalVenteMoyenneMensuelM);
			sessionConnect.setAttribute("ListeVenteMensuelMoyen1",
					ListeVenteMensuelMoyen);
			sessionConnect.setAttribute("MontantTotalVenteMoyenneMensuel",
					MontantTotalVenteMoyenneMensuel);

		} catch (Exception ex) {
			ex.printStackTrace();
		}
	}

	private void GetInformationVenteMensuelleMoyen(HttpServletRequest request) {
		try {

			List<WorkflowEntite> ListeVenteMensuelMoyen = new ArrayList<>();
			int IdVMM = Integer.parseInt(request.getParameter("IdVMM")
					.toString());
			ListeVenteMensuelMoyen = WDao
					.ListeVenteMensuelMoyenClientDPourModification(IdVMM);

			String LibelleMois = "";
			String Appreciation = "";
			double MontantVM = 0;

			for (WorkflowEntite wx : ListeVenteMensuelMoyen) {
				LibelleMois = wx.getLibellemois();
				Appreciation = wx.getAppreciation();
				MontantVM = wx.getMontantventemensuelmoyen();
			}
			request.setAttribute("IdVMM", IdVMM);
			request.setAttribute("LibelleMois", LibelleMois);
			request.setAttribute("Appreciation", Appreciation);
			request.setAttribute("MontantVM", MontantVM);

		} catch (Exception ex) {
			ex.printStackTrace();
		}
	}

	private void getInformationMapServlet(HttpServletRequest request,
			HttpServletResponse response) {
		try {
			// Exemple RDC → Kinshasa vers Matadi (test Afrique)
			request.setAttribute("srcLat", "-4.325");
			request.setAttribute("srcLon", "15.322");

			request.setAttribute("destLat", "-5.816");
			request.setAttribute("destLon", "13.450");

			request.getRequestDispatcher("/map.jsp").forward(request, response);
		} catch (Exception ex) {
			ex.printStackTrace();
		}
	}

